#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long ans = 0;
        for(int i=1;i<=N;i++){
            int x; scanf("%d", &x);
            if(x==i){
                long long contrib = (long long)i * (N - i + 1);
                ans += contrib;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

